final:
module top_module (
    input m,
    input a,
    input u,
    output reg invalid_c
);
    always @(*) begin
        case ({m, a, u})
            3'b010: invalid_c = 1'b1;
            3'b000: invalid_c = 1'b1;
            3'b011: invalid_c = 1'b1;
            3'b100: invalid_c = 1'b1;
            3'b111: invalid_c = 1'b0;
            3'b110: invalid_c = 1'b0;
            3'b101: invalid_c = 1'b1;
            3'b001: invalid_c = 1'b1;
        endcase
    end
endmodule
